const arr = Object.values($input.first().json.prices);

return [
  {
    json: {
      data: arr
    }
  }
];

const data = $input.first().json.data;

const sorted = data.sort((a, b) => b.pchange - a.pchange);

const gainers = sorted.slice(0, 10);
const losers = sorted.slice(-10).reverse();

return [
  {
    json: {
      top_gainers: gainers,
      top_losers: losers
    }
  }
];

const allItems = $input.all();

return [
  {
    json: {
      combinedData: allItems.map(item => item.json)
    }
  }
];
